/**
 * @fileoverview Pagination view — DOM rendering.
 * @module module/Pagination/view
 */

import { CLS, PART } from './constants.js';

/**
 * Generate page range with ellipsis.
 */
export function getPageRange(current, totalPages, siblingCount) {
    const range = [];
    const left  = Math.max(2, current - siblingCount);
    const right = Math.min(totalPages - 1, current + siblingCount);

    range.push(1);
    if (left > 2) range.push('...');
    for (let i = left; i <= right; i++) range.push(i);
    if (right < totalPages - 1) range.push('...');
    if (totalPages > 1) range.push(totalPages);

    return range;
}

const PREV_SVG = '<svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="14" height="14"><path d="M10 3L5 8L10 13"/></svg>';
const NEXT_SVG = '<svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="14" height="14"><path d="M6 3L11 8L6 13"/></svg>';

/**
 * Render pagination items.
 */
export function renderDOM(root, current, totalPages, siblingCount, config) {
    const el = root[0];
    el.innerHTML = '';

    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    const { size } = config;
    if (size === 'sm') {
        PART.SM_ROOT.apply(root);
    } else if (size === 'lg') {
        PART.LG_ROOT.apply(root);
    }

    el.setAttribute('role', 'navigation');
    el.setAttribute('aria-label', 'Pagination');

    // Prev
    const $prev = PART.PREV.create({
        role: 'button',
        'aria-label': 'Previous page',
        tabindex: '0',
    });
    $prev[0].innerHTML = PREV_SVG;
    if (current <= 1) $prev.addClass(CLS.DISABLED);
    root.append($prev);

    // Pages
    const range = getPageRange(current, totalPages, siblingCount);
    const pageEls = [];

    for (const page of range) {
        if (page === '...') {
            const $dots = PART.DOTS.create();
            $dots.text('\u2026');
            root.append($dots);
        } else {
            const $item = PART.ITEM.create({
                role: 'button',
                tabindex: '0',
            });
            $item.text(String(page));
            $item[0].dataset.page = String(page);
            if (page === current) $item[0].setAttribute('aria-current', 'page');
            if (page === current) $item.addClass(CLS.ACTIVE);
            root.append($item);
            pageEls.push($item[0]);
        }
    }

    // Next
    const $next = PART.NEXT.create({
        role: 'button',
        'aria-label': 'Next page',
        tabindex: '0',
    });
    $next[0].innerHTML = NEXT_SVG;
    if (current >= totalPages) $next.addClass(CLS.DISABLED);
    root.append($next);

    return { prevEl: $prev[0], nextEl: $next[0], pageEls };
}
