/**
 * @fileoverview Pagination barrel.
 * @module module/Pagination
 */
import { default as razyui } from '../index.js';
import { PaginationDef as DEF } from './Pagination.def.js';
import Pagination from './Pagination/index.js';

razyui.Pagination = Pagination;

if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, Pagination);
}

export default Pagination;

export const stylesheet = null;
