/**
 * @fileoverview Pagination constants.
 * @module module/Pagination/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

export const CLS = Object.freeze({
    ROOT:   'pagination',
    ITEM:   'pagination-item',
    PREV:   'pagination-prev',
    NEXT:   'pagination-next',
    ACTIVE: 'is-active',
    DISABLED: 'is-disabled',
    DOTS:   'pagination-dots',
});

export const DEFAULTS = Object.freeze({
    total: 0,
    pageSize: 10,
    current: 1,
    siblingCount: 1,
    size: 'md',
    onChange: null,
});

export const PART = defineParts('Pagination', {
    ROOT        : { class: 'pagination-container', aliases: ['root', 'container'] },
    ITEM        : { class: 'pagination-item', aliases: ['item', 'page'], tag: 'span' },
    PREV        : { class: 'pagination-prev', aliases: ['prev'], tag: 'span' },
    NEXT        : { class: 'pagination-next', aliases: ['next'], tag: 'span' },
    DOTS        : { class: 'pagination-dots', aliases: ['dots', 'ellipsis'], tag: 'span' },
    SM_ROOT     : { class: 'pagination-container-sm', aliases: ['sm'] },
    LG_ROOT     : { class: 'pagination-container-lg', aliases: ['lg'] },
});

PART.ROOT.jit     = 'inline-flex items-center gap-[var(--pn-gap)] [font-family:var(--pn-font-stack)] select-none';
PART.ITEM.jit     = 'flex items-center justify-center w-[var(--pn-size)] h-[var(--pn-size)] rounded-[var(--pn-radius)] text-[var(--pn-font-size)] fg-[var(--pn-text)] bg-[var(--pn-bg)] cursor-pointer ' + TRANSITION_COLORS + ' hover:bg-[var(--pn-bg-hover)] {is-active}:bg-[var(--pn-active-bg)] {is-active}:fg-[var(--pn-active-text)] {is-active}:pointer-events-none {is-disabled}:opacity-40 {is-disabled}:pointer-events-none';
PART.PREV.jit     = 'flex items-center justify-center w-[var(--pn-size)] h-[var(--pn-size)] rounded-[var(--pn-radius)] fg-[var(--pn-text)] bg-[var(--pn-bg)] cursor-pointer ' + TRANSITION_COLORS + ' hover:bg-[var(--pn-bg-hover)] {is-disabled}:opacity-40 {is-disabled}:pointer-events-none';
PART.NEXT.jit     = 'flex items-center justify-center w-[var(--pn-size)] h-[var(--pn-size)] rounded-[var(--pn-radius)] fg-[var(--pn-text)] bg-[var(--pn-bg)] cursor-pointer ' + TRANSITION_COLORS + ' hover:bg-[var(--pn-bg-hover)] {is-disabled}:opacity-40 {is-disabled}:pointer-events-none';
PART.DOTS.jit     = 'flex items-center justify-center w-[var(--pn-size)] h-[var(--pn-size)] fg-[var(--pn-text)] opacity-50 pointer-events-none';
PART.SM_ROOT.jit  = '[--pn-size:var(--pn-sm-size)] [--pn-font-size:var(--pn-sm-font-size)] [--pn-gap:var(--pn-sm-gap)]';
PART.LG_ROOT.jit  = '[--pn-size:var(--pn-lg-size)] [--pn-font-size:var(--pn-lg-font-size)] [--pn-gap:var(--pn-lg-gap)]';