/**
 * @fileoverview Pagination component — modular entry point.
 * @module module/Pagination
 */

import { default as razyui } from '../../index.js';
import { PaginationDef as DEF } from '../Pagination.def.js';
import { DEFAULTS } from './constants.js';
import { renderDOM } from './view.js';
import { emitEvent } from '../shared/emitEvent.js';

const Pagination = class {
    #root        = null;
    #destroyed = false;
    #config      = {};
    #current     = 1;
    #totalPages  = 1;
    #eventAC     = null;

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Pagination: element not found →', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        this.#current = this.#config.current;
        this.#totalPages = Math.max(1, Math.ceil(this.#config.total / this.#config.pageSize));
        this.#render();
    }

    #render() {
        this.#eventAC?.abort();

        const { prevEl, nextEl, pageEls } = renderDOM(
            this.#root, this.#current, this.#totalPages,
            this.#config.siblingCount, this.#config,
        );

        const ac = new AbortController();
        const opts = { signal: ac.signal };

        prevEl.addEventListener('click', () => this.prev(), opts);
        prevEl.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); this.prev(); } }, opts);

        nextEl.addEventListener('click', () => this.next(), opts);
        nextEl.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); this.next(); } }, opts);

        for (const el of pageEls) {
            el.addEventListener('click', () => this.goTo(Number(el.dataset.page)), opts);
            el.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); this.goTo(Number(el.dataset.page)); } }, opts);
        }

        this.#eventAC = ac;
    }

    goTo(page) {
        if (page < 1 || page > this.#totalPages || page === this.#current) return;
        this.#current = page;
        this.#render();
        emitEvent(this.#root[0], 'change', { value: page, page });
        this.#config.onChange?.(page);
    }

    prev() { this.goTo(this.#current - 1); }
    next() { this.goTo(this.#current + 1); }

    get current() { return this.#current; }
    get totalPages() { return this.#totalPages; }

    setTotal(total) {
        this.#config.total = total;
        this.#totalPages = Math.max(1, Math.ceil(total / this.#config.pageSize));
        if (this.#current > this.#totalPages) this.#current = this.#totalPages;
        this.#render();
    }

    getControl() {
        const self = this;
        return {
            goTo:     (p) => self.goTo(p),
            prev:     () => self.prev(),
            next:     () => self.next(),
            setTotal: (t) => self.setTotal(t),
            get current()    { return self.current; },
            get totalPages() { return self.totalPages; },
            destroy:  () => self.destroy(),
            get element() { return self.#root[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort(); this.#root[0].innerHTML = '';
    }
};

export default Pagination;
